SELECT COUNT(s.pk_siape) AS qtd_servidores FROM servidor s WHERE LOWER(s.categoria) = LOWER('docente') AND LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.sigla_campus) = LOWER('oes') AND LOWER(s.area_ingresso) LIKE LOWER('%artes%') AND s.saiu_do_ifg = FALSE AND CAST(strftime('%Y', s.data_ingresso_ifg) AS INTEGER) <= 2020 AND (CAST(strftime('%Y', COALESCE(s.data_criacao, s.data_atualizacao_lattes)) AS INTEGER) > 2020 OR COALESCE(s.data_criacao, s.data_atualizacao_lattes) IS NULL OR (CAST(strftime('%Y', COALESCE(s.data_criacao, s.data_atualizacao_lattes)) AS INTEGER) = 2020 AND CAST(strftime('%m', COALESCE(s.data_criacao, s.data_atualizacao_lattes)) AS INTEGER) > 6))